# pip install anthropic
from __future__ import annotations
import json
import os
import base64
from pathlib import Path
from typing import Any, Callable, Optional
import anthropic

client = anthropic.Anthropic(api_key=os.environ['ANTHROPIC_API_KEY'])
MODEL = 'claude-haiku-4-5-20251001'  # fast + cheap for tool use


# ── Tool definitions (Anthropic format) ───────────────────────────────────────

TOOLS = [
    {
        'name': 'get_weather',
        'description': 'Get current weather for a city. Returns temperature and conditions.',
        'input_schema': {  # Note: 'input_schema', not 'parameters'
            'type': 'object',
            'properties': {
                'city': {'type': 'string', 'description': 'City name'},
                'unit': {'type': 'string', 'enum': ['celsius', 'fahrenheit']},
            },
            'required': ['city'],
        },
    },
    {
        'name': 'search_database',
        'description': 'Search the product database. Returns matching products with prices.',
        'input_schema': {
            'type': 'object',
            'properties': {
                'query': {'type': 'string'},
                'category': {'type': 'string', 'enum': ['hardware', 'software', 'accessories']},
            },
            'required': ['query'],
        },
    },
    {
        'name': 'send_notification',
        'description': 'Send a notification to a user. Use only when explicitly asked to notify someone.',
        'input_schema': {
            'type': 'object',
            'properties': {
                'user_id': {'type': 'string'},
                'message': {'type': 'string'},
                'channel': {'type': 'string', 'enum': ['email', 'sms', 'push']},
            },
            'required': ['user_id', 'message', 'channel'],
        },
    },
]

# Tool implementations

def get_weather(city: str, unit: str = 'celsius') -> dict:
    data = {'Paris': {'temp_c': 18, 'condition': 'partly cloudy'}, 'Tokyo': {'temp_c': 28, 'condition': 'sunny'}}
    info = data.get(city, {'temp_c': 20, 'condition': 'unknown'})
    temp = info['temp_c'] if unit == 'celsius' else info['temp_c'] * 9/5 + 32
    return {'city': city, 'temperature': f'{temp}°{"C" if unit == "celsius" else "F"}', 'condition': info['condition']}

def search_database(query: str, category: Optional[str] = None) -> list[dict]:
    products = [
        {'name': 'Widget Pro', 'price': 29.99, 'category': 'hardware'},
        {'name': 'Code Editor', 'price': 49.99, 'category': 'software'},
        {'name': 'USB Hub', 'price': 19.99, 'category': 'accessories'},
    ]
    q = query.lower()
    results = [p for p in products if q in p['name'].lower()]
    if category:
        results = [p for p in results if p['category'] == category]
    return results or products[:2]

def send_notification(user_id: str, message: str, channel: str) -> dict:
    print(f'  [NOTIFICATION] To {user_id} via {channel}: {message}')
    return {'sent': True, 'channel': channel, 'user_id': user_id}

TOOL_FNS: dict[str, Callable] = {
    'get_weather': get_weather,
    'search_database': search_database,
    'send_notification': send_notification,
}


# ── Anthropic tool loop ────────────────────────────────────────────────────────

def anthropic_tool_loop(
    user_message: str,
    system: str = 'You are a helpful assistant.',
    max_rounds: int = 5,
    verbose: bool = True,
) -> str:
    messages = [{'role': 'user', 'content': user_message}]

    for round_num in range(max_rounds):
        response = client.messages.create(
            model=MODEL,
            max_tokens=1024,
            system=system,
            tools=TOOLS,
            messages=messages,
        )

        # Append assistant turn (all content blocks)
        messages.append({'role': 'assistant', 'content': response.content})

        if response.stop_reason == 'end_turn':  # no tool calls
            text_blocks = [b.text for b in response.content if hasattr(b, 'text')]
            return '\n'.join(text_blocks)

        # stop_reason == 'tool_use' — execute all tool blocks
        tool_results = []
        for block in response.content:
            if block.type == 'tool_use':
                fn = TOOL_FNS.get(block.name)
                if fn:
                    result = fn(**block.input)  # block.input is already a dict!
                    result_str = json.dumps(result)
                else:
                    result_str = json.dumps({'error': f'Unknown tool: {block.name}'})

                if verbose:
                    print(f'  [{round_num+1}] {block.name}({block.input}) → {result_str[:80]}')

                tool_results.append({
                    'type': 'tool_result',
                    'tool_use_id': block.id,
                    'content': result_str,
                })

        # Tool results go into a user message
        messages.append({'role': 'user', 'content': tool_results})

    return 'Max rounds reached'


# ── Cache control example ──────────────────────────────────────────────────────

def cached_system_prompt_call(
    user_question: str,
    large_context: str,
) -> str:
    """Use cache_control to reduce cost on repeated large contexts."""
    response = client.messages.create(
        model=MODEL,
        max_tokens=512,
        system=[
            {
                'type': 'text',
                'text': 'You are a helpful assistant. Answer based on the context provided.',
            },
            {
                'type': 'text',
                'text': large_context,
                'cache_control': {'type': 'ephemeral'},  # cache this large context
            },
        ],
        messages=[{'role': 'user', 'content': user_question}],
    )
    # Check if cache was used
    usage = response.usage
    print(f'  Input tokens: {usage.input_tokens}, Cache read: {getattr(usage, "cache_read_input_tokens", 0)}')
    return response.content[0].text


# ── Force specific tool ────────────────────────────────────────────────────────

def force_tool_call(message: str, tool_name: str) -> dict:
    """Force Claude to use a specific tool — useful for structured extraction."""
    response = client.messages.create(
        model=MODEL,
        max_tokens=512,
        tools=TOOLS,
        tool_choice={'type': 'tool', 'name': tool_name},  # force specific tool
        messages=[{'role': 'user', 'content': message}],
    )
    # Find the tool_use block
    for block in response.content:
        if block.type == 'tool_use' and block.name == tool_name:
            return block.input  # returns the arguments as dict
    return {}


# ── Demo ──────────────────────────────────────────────────────────────────────

if __name__ == '__main__':
    queries = [
        'What is the weather in Paris and Tokyo?',
        'Find me some hardware products and check the weather in Tokyo',
    ]

    print('=== Anthropic Tool Use Loop ===')
    for q in queries:
        print(f'\nQ: {q}')
        answer = anthropic_tool_loop(q)
        print(f'A: {answer}')

    print('\n=== Force Tool Call (structured extraction) ===')
    result = force_tool_call('I need weather for London please', 'get_weather')
    print(f'Extracted args: {result}')
    print(f'Weather: {get_weather(**result)}')

    print('\n=== Cache Control Demo ===')
    large_context = 'Company policy: ' + 'Our return policy allows 30 days. ' * 200  # ~800 tokens
    ans1 = cached_system_prompt_call('What is the return policy?', large_context)
    print(f'Answer: {ans1[:100]}')
    ans2 = cached_system_prompt_call('How long do I have to return?', large_context)  # should hit cache
    print(f'Answer (cached): {ans2[:100]}')
